const { lxc_id, operation, proxmox_host } = $('📥 Input').first().json;
if (!lxc_id || !operation) throw new Error('lxc_id und operation erforderlich');
const ops = ['snapshot', 'restore', 'health_check', 'start', 'stop', 'status', 'exec'];
if (!ops.includes(operation)) throw new Error(`Unbekannte Operation: ${operation}`);
const cmd = $('📥 Input').first().json.command || null;
if (operation === 'exec' && !cmd) throw new Error('command erforderlich für exec-Operation');
return { lxc_id, operation, proxmox_host: proxmox_host || '10.1.1.100', command: cmd,
  session_id: require('crypto').randomUUID(), timestamp: new Date().toISOString() };

const { lxc_id, operation, proxmox_host, command, session_id } = $input.first().json;
// pct exec / pct snapshot via SSH auf Proxmox
return { exit_code: 'success', session_id,
  data: { lxc_id, operation, command, result: `${operation} auf LXC ${lxc_id} ausgeführt` },
  timestamp: new Date().toISOString() };
